const headers = $json.headers ?? {};
const body = $json.body ?? $json;

// Configure aqui antes de ativar o workflow
const CONFIG = {
  webhookSecret: '', // opcional
  openaiApiKey: 'CHANGE_ME_OPENAI_API_KEY',
  openaiBaseUrl: 'https://api.openai.com/v1',
  transcriptionModel: 'gpt-4o-mini-transcribe',
  structuringModel: 'gpt-4o-mini',
  timeoutMs: 45000,
  maxAudioBytes: 10 * 1024 * 1024
};

const incomingSecret = headers['x-webhook-secret'] ?? headers['X-Webhook-Secret'] ?? null;
if (CONFIG.webhookSecret && incomingSecret !== CONFIG.webhookSecret) {
  return [{
    json: {
      process: false,
      statusCode: 401,
      body: { ok: false, error: 'Unauthorized notes transcription webhook secret.' }
    }
  }];
}

const audio = body.audio && typeof body.audio === 'object' ? body.audio : {};
const audioBase64 = String(audio.base64 ?? body.audioBase64 ?? '').trim();
const mimeType = String(audio.mimeType ?? body.mimeType ?? 'audio/webm').trim();
const language = String(audio.language ?? body.language ?? 'pt-BR').trim();
const modeRaw = String(body.mode ?? 'note').trim().toLowerCase();
const mode = modeRaw === 'transcript' ? 'transcript' : 'note';
const context = typeof body.context === 'string' ? body.context.trim() : '';

if (!audioBase64 || audioBase64.length < 32) {
  return [{
    json: {
      process: false,
      statusCode: 422,
      body: { ok: false, error: 'Payload inválido: audio.base64 obrigatório.' }
    }
  }];
}

if (!CONFIG.openaiApiKey || CONFIG.openaiApiKey.startsWith('CHANGE_ME_')) {
  return [{
    json: {
      process: false,
      statusCode: 500,
      body: { ok: false, error: 'Configure CONFIG.openaiApiKey no node Normalize Notes Payload.' }
    }
  }];
}

let estimatedBytes = 0;
try {
  estimatedBytes = Math.floor((audioBase64.length * 3) / 4);
} catch (_) {
  estimatedBytes = 0;
}

if (estimatedBytes > CONFIG.maxAudioBytes) {
  return [{
    json: {
      process: false,
      statusCode: 413,
      body: { ok: false, error: `Áudio excede o limite de ${Math.round(CONFIG.maxAudioBytes / 1024 / 1024)}MB.` }
    }
  }];
}

return [{
  json: {
    process: true,
    audioBase64,
    mimeType,
    language,
    mode,
    context,
    openaiApiKey: CONFIG.openaiApiKey,
    openaiBaseUrl: CONFIG.openaiBaseUrl,
    transcriptionModel: CONFIG.transcriptionModel,
    structuringModel: CONFIG.structuringModel,
    timeoutMs: CONFIG.timeoutMs
  }
}];

const startedAt = Date.now();
const baseUrl = String($json.openaiBaseUrl || 'https://api.openai.com/v1').replace(/\/$/, '');
const apiKey = String($json.openaiApiKey || '');

const controller = new AbortController();
const timeout = setTimeout(() => controller.abort(), Number($json.timeoutMs || 45000));

try {
  const audioBuffer = Buffer.from(String($json.audioBase64), 'base64');
  if (!audioBuffer || audioBuffer.length === 0) {
    return [{ json: { statusCode: 422, body: { ok: false, error: 'Base64 de áudio inválido.' } } }];
  }

  const blob = new Blob([audioBuffer], { type: String($json.mimeType || 'audio/webm') });
  const formData = new FormData();
  formData.append('file', blob, 'notes-recording.webm');
  formData.append('model', String($json.transcriptionModel || 'gpt-4o-mini-transcribe'));
  formData.append('language', String($json.language || 'pt-BR'));

  const transcriptionResponse = await fetch(`${baseUrl}/audio/transcriptions`, {
    method: 'POST',
    headers: { Authorization: `Bearer ${apiKey}` },
    body: formData,
    signal: controller.signal
  });

  const transcriptionRaw = await transcriptionResponse.text();
  if (!transcriptionResponse.ok) {
    return [{
      json: {
        statusCode: 502,
        body: {
          ok: false,
          error: `Falha na transcrição (${transcriptionResponse.status}).`,
          detail: transcriptionRaw.slice(0, 600)
        }
      }
    }];
  }

  let transcript = '';
  try {
    const parsed = JSON.parse(transcriptionRaw);
    transcript = String(parsed.text ?? parsed.transcript ?? '').trim();
  } catch (_) {
    transcript = String(transcriptionRaw || '').trim();
  }

  if (!transcript) {
    return [{ json: { statusCode: 502, body: { ok: false, error: 'Transcrição vazia retornada pelo provedor.' } } }];
  }

  if (String($json.mode) === 'transcript') {
    clearTimeout(timeout);
    return [{
      json: {
        statusCode: 200,
        body: {
          ok: true,
          provider: 'n8n-openai',
          transcript,
          titleSuggestion: null,
          structuredContent: transcript,
          tags: [],
          confidence: null,
          durationMs: Date.now() - startedAt
        }
      }
    }];
  }

  const systemPrompt = [
    'Você recebe uma transcrição de áudio em português e deve devolver SOMENTE JSON válido.',
    'Formato obrigatório com chaves: titleSuggestion, structuredContent, tags, confidence.',
    'structuredContent deve ser markdown executivo: Resumo, Decisões, Próximos passos, Pendências.',
    'tags deve ter no máximo 8 itens curtos.'
  ].join('\n');

  const userPrompt = [
    `Contexto: ${String($json.context || 'nota geral')}`,
    'Transcrição:',
    transcript
  ].join('\n\n');

  const chatResponse = await fetch(`${baseUrl}/chat/completions`, {
    method: 'POST',
    headers: {
      Authorization: `Bearer ${apiKey}`,
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      model: String($json.structuringModel || 'gpt-4o-mini'),
      temperature: 0.2,
      response_format: { type: 'json_object' },
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userPrompt }
      ]
    }),
    signal: controller.signal
  });

  const chatRaw = await chatResponse.text();
  let structuredContent = transcript;
  let titleSuggestion = null;
  let confidence = null;
  let tags = [];

  if (chatResponse.ok) {
    try {
      const parsed = JSON.parse(chatRaw);
      const content = parsed?.choices?.[0]?.message?.content ?? '';
      const payload = JSON.parse(String(content || '{}'));

      structuredContent = typeof payload.structuredContent === 'string' && payload.structuredContent.trim()
        ? payload.structuredContent.trim()
        : transcript;
      titleSuggestion = typeof payload.titleSuggestion === 'string' && payload.titleSuggestion.trim()
        ? payload.titleSuggestion.trim().slice(0, 120)
        : null;
      confidence = typeof payload.confidence === 'number' ? payload.confidence : null;
      tags = Array.isArray(payload.tags)
        ? Array.from(new Set(payload.tags
            .map((tag) => (typeof tag === 'string' ? tag.trim().toLowerCase() : ''))
            .filter((tag) => tag.length > 0)))
            .slice(0, 8)
        : [];
    } catch (_) {
      // fallback para transcript puro
    }
  }

  clearTimeout(timeout);
  return [{
    json: {
      statusCode: 200,
      body: {
        ok: true,
        provider: 'n8n-openai',
        transcript,
        titleSuggestion,
        structuredContent,
        tags,
        confidence,
        durationMs: Date.now() - startedAt
      }
    }
  }];
} catch (error) {
  clearTimeout(timeout);

  const message = error && error.name === 'AbortError'
    ? 'Timeout na transcrição/estruturação.'
    : `Erro no gateway de transcrição: ${error.message || 'desconhecido'}`;

  return [{
    json: {
      statusCode: error && error.name === 'AbortError' ? 504 : 502,
      body: { ok: false, error: message }
    }
  }];
}
